content = '<!DOCTYPE html>\n<html lang="pt-BR" class="dark">\n<head>\n    <meta charset="UTF-8">\n    <meta name="viewport" content="width=device-width, initial-scale=1.0">\n    <title>Monitor de Opções B3 PRO | Antigravity</title>\n    <link rel="preconnect" href="https://fonts.googleapis.com">\n    <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>\n    <link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&family=JetBrains+Mono:wght@400;500;700&display=swap" rel="stylesheet">\n    <script src="https://cdn.tailwindcss.com"></script>\n    <script src="https://unpkg.com/lightweight-charts@4.1.3/dist/lightweight-charts.standalone.production.js"></script>\n    <script>\n        tailwind.config = {\n            darkMode: \'class\',\n            theme: {\n                extend: {\n                    fontFamily: { sans: [\'Inter\', \'sans-serif\'], mono: [\'JetBrains Mono\', \'monospace\'] },\n                    colors: {\n                        dark: { 900: \'#030712\', 800: \'#111827\', 700: \'#1f2937\', 600: \'#374151\' },\n                        brand: { DEFAULT: \'#3b82f6\', purple: \'#8b5cf6\', gold: \'#f59e0b\' }\n                    }\n                }\n            }\n        }\n    </script>\n    <style>\n        body { background-color: #030712; color: #f3f4f6; min-height: 100vh; font-family: \'Inter\', sans-serif; }\n        .glass-card { background: rgba(17, 24, 39, 0.65); backdrop-filter: blur(16px); border: 1px solid rgba(255, 255, 255, 0.05); }\n        .badge-pro { background: linear-gradient(135deg, #f59e0b 0%, #d97706 100%); -webkit-background-clip: text; background-clip: text; -webkit-text-fill-color: transparent; font-weight: 700; }\n        #chart-modal { display: none; position: fixed; inset: 0; z-index: 999; background: rgba(3, 7, 18, 0.85); backdrop-filter: blur(12px); align-items: center; justify-content: center; }\n        #chart-modal.open { display: flex; }\n        #chart-modal-box { background: #111827; border: 1px solid #1f2937; border-radius: 1rem; width: 100%; max-width: 900px; overflow: hidden; }\n        #chart-container { height: 340px; }\n    </style>\n</head>\n<body class="bg-[#030712]">\n    <nav class="sticky top-0 z-50 glass-card border-b border-dark-700/50 px-6 py-4">\n        <div class="max-w-7xl mx-auto flex justify-between items-center">\n            <div class="flex items-center gap-3">\n                <img src="logo.png" class="w-10 h-10 rounded-lg" />\n                <div>\n                    <h1 class="text-xl font-bold text-white">ThetaLens <span class="badge-pro text-sm px-2 py-0.5 border border-brand-gold/30 rounded ml-1">PRO</span></h1>\n                    <p class="text-xs text-gray-400">Terminal de Inteligência Quantitativa</p>\n                </div>\n            </div>\n            <div class="flex items-center gap-6 text-sm font-medium text-gray-400">\n                <div class="hidden md:flex gap-4">\n                    <span>Screener</span>\n                    <span>Estratégias</span>\n                </div>\n                <button id="btn-radar" onclick="toggleRadar()" class="flex items-center gap-2 px-3 py-1.5 rounded-md bg-dark-800 border border-dark-700 group">\n                    <span class="w-2 h-2 rounded-full bg-gray-500 group-[.active]:bg-emerald-500" id="radar-led"></span>\n                    <span class="text-[11px] font-bold uppercase hidden sm:inline">Radar</span>\n                </button>\n                <div class="px-3 py-1.5 rounded-md bg-dark-800 border border-brand-purple/30">\n                    <span class="text-[11px] font-bold text-brand-purple">DTE: <span id="dte-counter" class="text-white">--</span></span>\n                </div>\n            </div>\n        </div>\n    </nav>\n\n    <main class="max-w-7xl mx-auto px-6 py-8">\n        <div class="mb-6 p-4 rounded-xl border border-rose-500/30 bg-rose-500/10 text-sm text-gray-300">\n            <strong class="text-rose-400 font-bold">AVISO:</strong> Este painel é educacional. Não é recomendação. Decisões próprias e profissionais.\n        </div>\n        <div class="grid grid-cols-1 md:grid-cols-3 gap-6" id="assets-grid"></div>\n    </main>\n\n    <div id="chart-modal" onclick="if(event.target===this)closeChart()">\n        <div id="chart-modal-box">\n           <div class="p-4 border-b border-gray-800 flex justify-between"><h3 id="modal-ticker" class="text-xl font-bold"></h3><button onclick="closeChart()">X</button></div>\n           <div id="chart-container"></div>\n        </div>\n    </div>\n\n    <script>\n        const assetsData = [\n            { ticker: \'PETR4\', company: \'Petrobras\', price: 0, change: 0, bands: { daily: { upper: 0, lower: 0 } } },\n            { ticker: \'VALE3\', company: \'Vale S.A.\', price: 0, change: 0, bands: { daily: { upper: 0, lower: 0 } } },\n            { ticker: \'BBAS3\', company: \'Banco do Brasil\', price: 0, change: 0, bands: { daily: { upper: 0, lower: 0 } } }\n        ];\n\n        const fmtMoney = (v) => new Intl.NumberFormat(\'pt-BR\', { style: \'currency\', currency: \'BRL\' }).format(v);\n        const BRAPI_TOKEN = \'ip1K3nN5Z9vhEgZ8jbiyHT\';\n\n        async function init() {\n            for(const a of assetsData) {\n                try {\n                    const r = await fetch(`https://brapi.dev/api/quote/${a.ticker}?range=1mo&interval=1d&token=${BRAPI_TOKEN}`);\n                    const d = await r.json();\n                    if(d.results?.[0]) {\n                        const q = d.results[0];\n                        a.price = q.regularMarketPrice;\n                        a.change = q.regularMarketChangePercent;\n                        const h = q.historicalDataPrice.map(x => x.close).filter(x => x > 0);\n                        const m = h.slice(-20).reduce((s, x) => s + x, 0) / 20;\n                        const sd = Math.sqrt(h.slice(-20).reduce((s, x) => s + (x-m)**2, 0) / 19);\n                        a.bands.daily.upper = m + 2*sd;\n                        a.bands.daily.lower = m - 2*sd;\n                    }\n                } catch(e) {}\n            }\n            render();\n            setInterval(updateDTE, 60000); updateDTE();\n        }\n\n        function render() {\n            const g = document.getElementById(\'assets-grid\'); g.innerHTML = \'\';\n            for(const a of assetsData) {\n                const p = Math.max(0, Math.min(100, ((a.price - a.bands.daily.lower) / (a.bands.daily.upper - a.bands.daily.lower)) * 100));\n                g.innerHTML += `\n                    <div class="glass-card p-6 rounded-2xl">\n                        <div class="flex justify-between mb-4">\n                            <h3 class="text-2xl font-bold">${a.ticker}</h3>\n                            <div class="text-right"><p class="text-xl font-mono">${fmtMoney(a.price)}</p></div>\n                        </div>\n                        <div class="mt-4">\n                            <div class="flex justify-between text-[10px] uppercase font-bold text-gray-500 mb-1"><span>Banda Diária</span><span>${Math.round(p)}%</span></div>\n                            <div class="w-full h-2 bg-gray-800 rounded-full overflow-hidden border border-gray-700">\n                                <div class="h-full bg-brand transition-all duration-1000" style="width: ${p}%"></div>\n                            </div>\n                        </div>\n                        <button onclick="openChart(\'${a.ticker}\')" class="w-full mt-6 py-2 bg-gray-800 rounded-lg text-xs font-bold uppercase tracking-widest text-gray-400 hover:bg-gray-700">Ver Gráfico</button>\n                    </div>`;\n            }\n        }\n\n        function updateDTE() {\n            const d = document.getElementById(\'dte-counter\');\n            const now = new Date();\n            let t = new Date(now.getFullYear(), now.getMonth(), 15);\n            while(t.getDay() !== 5) t.setDate(t.getDate() + 1);\n            if(now > t) { t = new Date(now.getFullYear(), now.getMonth()+1, 15); while(t.getDay() !== 5) t.setDate(t.getDate() + 1); }\n            d.textContent = Math.ceil((t - now) / 864e5);\n        }\n\n        async function toggleRadar() {\n            const b = document.getElementById(\'btn-radar\');\n            if(b.classList.toggle(\'active\')) {\n                const p = await Notification.requestPermission();\n                if(p === \'granted\') new Notification("Radar Ativo", { body: "Monitorando extremos." });\n                else b.classList.remove(\'active\');\n            }\n        }\n\n        function openChart(t) { document.getElementById(\'modal-ticker\').textContent = t; document.getElementById(\'chart-modal\').classList.add(\'open\'); loadChart(t); }\n        function closeChart() { document.getElementById(\'chart-modal\').classList.remove(\'open\'); }\n        async function loadChart(t) {\n            const container = document.getElementById(\'chart-container\'); container.innerHTML = \'\';\n            const r = await fetch(`https://brapi.dev/api/quote/${t}?range=3mo&interval=1d&token=${BRAPI_TOKEN}`);\n            const d = await r.json();\n            const h = d.results[0].historicalDataPrice;\n            const chart = LightweightCharts.createChart(container, { width: container.offsetWidth, height: 340, layout: { background: { color: \'transparent\' }, textColor: \'#ccc\' } });\n            const s = chart.addCandlestickSeries();\n            s.setData(h.map(x => ({ time: x.date, open: x.open, high: x.high, low: x.low, close: x.close })));\n            chart.timeScale().fitContent();\n        }\n\n        init();\n    </script>\n</body>\n</html>\n'
with open("index.html", "w", encoding="utf-8") as out:
    out.write(content)
